module gray_counter(clk, rst, gray);

    input clk;
    input rst;
    output [4:0] gray;
    reg [4:0] obf_bin;
    reg [4:0] gray;

    always @(posedge clk)
    begin
        if (rst)
            obf_bin <= 5'b00000;
        else
            obf_bin <= obf_bin + 1;
    end

    always @(*)
    begin
        gray = obf_bin ^ (obf_bin >> 1);
    end

endmodule
